/**
 * Cross-runtime short-text contract parity test (WASM/JS).
 *
 * Loads tests/fixtures/short_text/contract.json and verifies that this
 * runtime's exported short-text constants and behaviour match the spec.
 *
 * Spec: docs/spec/short-text-contract.toml.
 * Fixture is regenerated by scripts/regenerate_short_text_fixture.py.
 *
 * What is checked:
 *   - Exported constants (MIN_PHONEME_IDS, MIN_BODY_FOR_STRATEGY_A,
 *     DEFAULT_HOP_SIZE) match the contract values byte-for-byte.
 *   - `padPhonemeIds` uses pause_token_id = 0 and pads up to
 *     min_phoneme_ids when the body length is at least
 *     min_body_for_strategy_a.
 *   - `adjustScalesForShortInput` clamps to scales.noise_scale_min_ratio
 *     (0.5) and scales.noise_w_min_ratio (0.4).
 *
 * What is NOT checked here (Strategy C is intentionally not implemented in
 * the WASM runtime — see CLAUDE.md):
 *   - ssml_injection.short_text_chars / silence_pad_ms / skip_if_ssml
 *
 * What is checked behaviourally only (private constants in index.js):
 *   - trim.threshold_rms (0.01) and trim.min_samples (2205)
 */

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

import {
  MIN_PHONEME_IDS,
  MIN_BODY_FOR_STRATEGY_A,
  DEFAULT_HOP_SIZE,
  padPhonemeIds,
  adjustScalesForShortInput,
} from "../../src/index.js";

const __dirname = dirname(fileURLToPath(import.meta.url));
const FIXTURE_PATH = resolve(__dirname, "../../../../../tests/fixtures/short_text/contract.json");
const INDEX_SOURCE_PATH = resolve(__dirname, "../../src/index.js");

const fixture = JSON.parse(readFileSync(FIXTURE_PATH, "utf-8"));

describe("short-text contract — WASM/JS exported constants", () => {
  it("MIN_PHONEME_IDS matches contract padding.min_phoneme_ids", () => {
    assert.strictEqual(MIN_PHONEME_IDS, fixture.padding.min_phoneme_ids);
  });

  it("MIN_BODY_FOR_STRATEGY_A matches contract padding.min_body_for_strategy_a", () => {
    assert.strictEqual(MIN_BODY_FOR_STRATEGY_A, fixture.padding.min_body_for_strategy_a);
  });

  it("DEFAULT_HOP_SIZE is 256 (matches Python timing default_hop_length)", () => {
    assert.strictEqual(DEFAULT_HOP_SIZE, 256);
  });
});

describe("short-text contract — WASM/JS behavioural parity", () => {
  it("padPhonemeIds inserts pause_token_id (0) up to min_phoneme_ids", () => {
    const expectedPause = fixture.padding.pause_token_id;
    const expectedTarget = fixture.padding.min_phoneme_ids;

    // Body length 5 (= 7 ids inc. BOS/EOS) so Strategy A applies and pads.
    const bos = 1;
    const eos = 2;
    const body = [10, 11, 12, 13, 14];
    const phonemeIds = [bos, ...body, eos];

    const result = padPhonemeIds(phonemeIds, null);

    assert.strictEqual(result.wasPadded, true, "should be padded");
    assert.strictEqual(
      result.phonemeIds.length,
      expectedTarget,
      `padded length should be min_phoneme_ids (=${expectedTarget})`
    );

    // BOS and EOS must remain at the original boundaries.
    assert.strictEqual(result.phonemeIds[0], bos, "BOS must remain at index 0");
    assert.strictEqual(
      result.phonemeIds[result.phonemeIds.length - 1],
      eos,
      "EOS must remain at the last index"
    );

    // All inserted slots must be the canonical pause token.
    const padCount = expectedTarget - phonemeIds.length;
    let pauseSeen = 0;
    for (const id of result.phonemeIds) {
      if (id === expectedPause && id !== bos && id !== eos) {
        pauseSeen++;
      }
    }
    assert.ok(
      pauseSeen >= padCount,
      `expected at least ${padCount} pause tokens (id=${expectedPause}), saw ${pauseSeen}`
    );

    // frontPad + backPad equals the total padding count.
    assert.strictEqual(result.frontPad + result.backPad, padCount);
  });

  it("padPhonemeIds skips Strategy A when body < min_body_for_strategy_a", () => {
    // Body length 1 — less than min_body_for_strategy_a (=3). Should NOT pad.
    const phonemeIds = [1, 10, 2];
    const result = padPhonemeIds(phonemeIds, null);
    assert.strictEqual(result.wasPadded, false);
    assert.deepStrictEqual(result.phonemeIds, phonemeIds);
  });

  it("padPhonemeIds skips when length already >= min_phoneme_ids", () => {
    const phonemeIds = Array.from({ length: fixture.padding.min_phoneme_ids + 5 }, (_, i) =>
      i === 0 ? 1 : i === 19 ? 2 : 10 + i
    );
    const result = padPhonemeIds(phonemeIds, null);
    assert.strictEqual(result.wasPadded, false);
  });

  it("adjustScalesForShortInput clamps to noise_scale_min_ratio", () => {
    const minRatio = fixture.scales.noise_scale_min_ratio;
    const noiseScale = 1.0;
    const noiseW = 1.0;

    // phonemeCount=1 forces ratio=1/15, well below the floor.
    const out = adjustScalesForShortInput(1, noiseScale, noiseW);
    // Must equal exactly noiseScale * noise_scale_min_ratio (clamped).
    assert.strictEqual(
      out.noiseScale,
      noiseScale * minRatio,
      `expected ${noiseScale * minRatio} got ${out.noiseScale}`
    );
  });

  it("adjustScalesForShortInput clamps to noise_w_min_ratio", () => {
    const minWRatio = fixture.scales.noise_w_min_ratio;
    const noiseW = 1.0;

    const out = adjustScalesForShortInput(1, 1.0, noiseW);
    assert.strictEqual(
      out.noiseW,
      noiseW * minWRatio,
      `expected ${noiseW * minWRatio} got ${out.noiseW}`
    );
  });

  it("adjustScalesForShortInput passes through when phonemeCount >= MIN_PHONEME_IDS", () => {
    const out = adjustScalesForShortInput(MIN_PHONEME_IDS, 0.667, 0.8);
    assert.strictEqual(out.noiseScale, 0.667);
    assert.strictEqual(out.noiseW, 0.8);
  });
});

describe("short-text contract — index.js source-level constants (private)", () => {
  // These constants are intentionally non-exported (internal trim helpers),
  // so we verify them via source inspection rather than runtime import.
  // This catches drift between the constant declaration and the spec.
  const indexSrc = readFileSync(INDEX_SOURCE_PATH, "utf-8");

  it("TRIM_THRESHOLD_RMS literal matches contract trim.threshold_rms", () => {
    const expected = fixture.trim.threshold_rms;
    const re = /const\s+TRIM_THRESHOLD_RMS\s*=\s*([0-9.]+)\s*;/m;
    const m = re.exec(indexSrc);
    assert.ok(m, "TRIM_THRESHOLD_RMS declaration not found in src/index.js");
    assert.strictEqual(parseFloat(m[1]), expected);
  });

  it("TRIM_MIN_SAMPLES literal matches contract trim.min_samples", () => {
    const expected = fixture.trim.min_samples;
    const re = /const\s+TRIM_MIN_SAMPLES\s*=\s*([0-9]+)\s*;/m;
    const m = re.exec(indexSrc);
    assert.ok(m, "TRIM_MIN_SAMPLES declaration not found in src/index.js");
    assert.strictEqual(parseInt(m[1], 10), expected);
  });
});

describe("short-text contract — Strategy C (NOT implemented in WASM)", () => {
  // Strategy C (SSML silence injection) is intentionally not part of the
  // WASM runtime per CLAUDE.md ("SSML 4 ランタイムのみ: Python/Rust/C#/Go").
  // The spec entries for short_text_chars / silence_pad_ms are still
  // tracked here so future implementation work can wire them up against
  // this contract test.
  it.todo(
    "WASM runtime does not implement Strategy C — short_text_chars / silence_pad_ms / skip_if_ssml"
  );

  it("contract values are present so a future Strategy C impl can adopt them", () => {
    assert.strictEqual(typeof fixture.ssml_injection.short_text_chars, "number");
    assert.strictEqual(typeof fixture.ssml_injection.silence_pad_ms, "number");
    assert.strictEqual(typeof fixture.ssml_injection.skip_if_ssml, "boolean");
  });
});
